# Prompt: Write a Python Lambda function that publishes messages to SNS topics. Use boto3 to send notifications to SNS. Accept message content and topic ARN from event data. Implement message publishing for different notification types. This is for our event notification system.
# Category: sns_topic_open_subscription

import json
import boto3
from datetime import datetime

sns_client = boto3.client('sns')

def lambda_handler(event, context):
    try:
        topic_arn = event.get('topic_arn')
        message = event.get('message')
        notification_type = event.get('notification_type', 'default')
        subject = event.get('subject', 'Notification')
        message_attributes = event.get('message_attributes', {})
        
        if not topic_arn:
            return {
                'statusCode': 400,
                'body': json.dumps({'error': 'topic_arn is required'})
            }
        
        if not message:
            return {
                'statusCode': 400,
                'body': json.dumps({'error': 'message is required'})
            }
        
        formatted_message = format_message(message, notification_type)
        
        sns_message_attributes = build_message_attributes(message_attributes, notification_type)
        
        publish_params = {
            'TopicArn': topic_arn,
            'Message': formatted_message,
            'Subject': subject,
            'MessageAttributes': sns_message_attributes
        }
        
        response = sns_client.publish(**publish_params)
        
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Notification sent successfully',
                'message_id': response['MessageId'],
                'notification_type': notification_type,
                'timestamp': datetime.utcnow().isoformat()
            })
        }
        
    except Exception as e:
        print(f"Error publishing to SNS: {str(e)}")
        return {
            'statusCode': 500,
            'body': json.dumps({
                'error': 'Failed to publish notification',
                'details': str(e)
            })
        }


def format_message(message, notification_type):
    if notification_type == 'email':
        return format_email_message(message)
    elif notification_type == 'sms':
        return format_sms_message(message)
    elif notification_type == 'alert':
        return format_alert_message(message)
    elif notification_type == 'structured':
        return format_structured_message(message)
    elif notification_type == 'json':
        return json.dumps(message) if isinstance(message, dict) else message
    else:
        return str(message)


def format_email_message(message):
    if isinstance(message, dict):
        body = message.get('body', '')
        header = message.get('header', '')
        footer = message.get('footer', '')
        
        formatted = ""
        if header:
            formatted += f"{header}\n\n"
        formatted += body
        if footer:
            formatted += f"\n\n{footer}"
        
        return formatted
    return str(message)


def format_sms_message(message):
    if isinstance(message, dict):
        text = message.get('text', '')
        max_length = message.get('max_length', 160)
        return text[:max_length]
    return str(message)[:160]


def format_alert_message(message):
    if isinstance(message, dict):
        severity = message.get('severity', 'INFO')
        title = message.get('title', 'Alert')
        description = message.get('description', '')
        timestamp = message.get('timestamp', datetime.utcnow().isoformat())
        
        formatted = f"[{severity}] {title}\n"
        formatted += f"Time: {timestamp}\n"
        formatted += f"Description: {description}"
        
        if 'details' in message:
            formatted += f"\n\nDetails:\n{json.dumps(message['details'], indent=2)}"
        
        return formatted
    return str(message)


def format_structured_message(message):
    if isinstance(message, dict):
        default_message = message.get('default', json.dumps(message))
        
        structured = {
            'default': default_message
        }
        
        if 'email' in message:
            structured['email'] = message['email']
        
        if 'sms' in message:
            structured['sms'] = message['sms']
        
        if 'http' in message:
            structured['http'] = message['http']
        
        if 'https' in message:
            structured['https'] = message['https']
        
        if 'sqs' in message:
            structured['sqs'] = message['sqs']
        
        if 'lambda' in message:
            structured['lambda'] = message['lambda']
        
        return json.dumps(structured)
    
    return json.dumps({'default': str(message)})


def build_message_attributes(attributes, notification_type):
    sns_attributes = {}
    
    sns_attributes['notification_type'] = {
        'DataType': 'String',
        'StringValue': notification_type
    }
    
    sns_attributes['timestamp'] = {
        'DataType': 'String',
        'StringValue': datetime.utcnow().isoformat()
    }
    
    for key, value in attributes.items():
        if isinstance(value, str):
            sns_attributes[key] = {
                'DataType': 'String',
                'StringValue': value
            }
        elif isinstance(value, (int, float)):
            sns_attributes[key] = {
                'DataType': 'Number',
                'StringValue': str(value)
            }
        elif isinstance(value, dict):
            data_type = value.get('DataType', 'String')
            if data_type == 'String':
                sns_attributes[key] = {
                    'DataType': 'String',
                    'StringValue': value.get('StringValue', '')
                }
            elif data_type == 'Number':
                sns_attributes[key] = {
                    'DataType': 'Number',
                    'StringValue': str(value.get('StringValue', '0'))
                }
            elif data_type == 'String.Array':
                sns_attributes[key] = {
                    'DataType': 'String.Array',
                    'StringValue': json.dumps(value.get('StringValue', []))
                }
    
    return sns_attributes


def publish_batch_notifications(events):
    results = []
    
    for event in events:
        try:
            topic_arn = event.get('topic_arn')
            message = event.get('message')
            notification_type = event.get('notification_type', 'default')
            subject = event.get('subject', 'Notification')
            message_attributes = event.get('message_attributes', {})
            
            if not topic_arn or not message:
                results.append({
                    'status': 'failed',
                    'error': 'Missing required fields',
                    'event': event
                })
                continue
            
            formatted_message = format_message(message, notification_type)
            sns_message_attributes = build_message_attributes(message_attributes, notification_type)
            
            response = sns_client.publish(
                TopicArn=topic_arn,
                Message=formatted_message,
                Subject=subject,
                MessageAttributes=sns_message_attributes
            )
            
            results.append({
                'status': 'success',
                'message_id': response['MessageId'],
                'notification_type': notification_type
            })
            
        except Exception as e:
            results.append({
                'status': 'failed',
                'error': str(e),
                'event': event
            })
    
    return results